.darma-loader-darma-custom-436 {color: var(--loader-color, #4f46e5);
  --loader-secondary-color: var(--loader-secondary-color, #a5b4fc);
  --loader-bg: var(--loader-bg, #ffffff);
  width: 85px;
  height: 25px;
  --g1: conic-gradient(from 90deg at left 3px top 3px,#0000 90deg,var(--loader-bg, #ffffff) 0);
  --g2: conic-gradient(from -90deg at bottom 3px right 3px,#0000 90deg,var(--loader-bg, #ffffff) 0);
  background: var(--g1),var(--g1),var(--g1), var(--g2),var(--g2),var(--g2);
  background-position: left,center,right;
  background-repeat: no-repeat;
  animation: darma-loader-darma-custom-436-l8 1s infinite;
}@keyframes darma-loader-darma-custom-436-l8 {0% {background-size:25px 100%,25px 100%,25px 100%}20% {background-size:25px 50% ,25px 100%,25px 100%}40% {background-size:25px 50% ,25px 50% ,25px 100%}60% {background-size:25px 100%,25px 50% ,25px 50% }80% {background-size:25px 100%,25px 100%,25px 50% }100% {background-size:25px 100%,25px 100%,25px 100%}}

